import{_ as i,o as e,c as l,ak as s}from"./chunks/framework.24mNDJkT.js";const p=JSON.parse('{"title":"数据链路层协议与总结笔记","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/物理层和数据链路层/链路层常用协议.md","filePath":"计算机网络/物理层和数据链路层/链路层常用协议.md","lastUpdated":1775135228000}'),r={name:"计算机网络/物理层和数据链路层/链路层常用协议.md"};function n(h,a,t,d,o,c){return e(),l("div",null,[...a[0]||(a[0]=[s(`<h1 id="数据链路层协议与总结笔记" tabindex="-1">数据链路层协议与总结笔记 <a class="header-anchor" href="#数据链路层协议与总结笔记" aria-label="Permalink to “数据链路层协议与总结笔记”">​</a></h1><h2 id="一、数据链路层回顾" tabindex="-1">一、数据链路层回顾 <a class="header-anchor" href="#一、数据链路层回顾" aria-label="Permalink to “一、数据链路层回顾”">​</a></h2><h3 id="核心作用" tabindex="-1">核心作用 <a class="header-anchor" href="#核心作用" aria-label="Permalink to “核心作用”">​</a></h3><blockquote><p><strong>解决数据包在一个网络 / 一段链路上的传输问题</strong></p></blockquote><hr><h3 id="链路的定义" tabindex="-1">链路的定义 <a class="header-anchor" href="#链路的定义" aria-label="Permalink to “链路的定义”">​</a></h3><ul><li>一段链路 = <strong>两个节点之间的物理连接</strong></li><li>条件： <ul><li>中间<strong>没有路由器</strong></li></ul></li></ul><hr><h3 id="举例理解" tabindex="-1">举例理解 <a class="header-anchor" href="#举例理解" aria-label="Permalink to “举例理解”">​</a></h3><ul><li>✔ 同一链路（局域网）： <ul><li>主机 ↔ 主机</li><li>主机 ↔ 路由器接口</li></ul></li><li>❌ 不同链路： <ul><li>跨路由器通信</li></ul></li></ul><hr><h2 id="二、mac-地址机制-核心" tabindex="-1">二、MAC 地址机制（核心） <a class="header-anchor" href="#二、mac-地址机制-核心" aria-label="Permalink to “二、MAC 地址机制（核心）”">​</a></h2><h3 id="基本特性" tabindex="-1">基本特性 <a class="header-anchor" href="#基本特性" aria-label="Permalink to “基本特性”">​</a></h3><ul><li>长度：6 字节（48 位）</li><li>又叫：物理地址</li><li>存储位置：网卡（NIC）</li><li>特点： <ul><li>出厂固化（全球唯一）</li><li>操作系统可“伪造”（可修改）</li></ul></li></ul><hr><h3 id="特殊-mac-地址" tabindex="-1">特殊 MAC 地址 <a class="header-anchor" href="#特殊-mac-地址" aria-label="Permalink to “特殊 MAC 地址”">​</a></h3><ul><li>广播地址：</li></ul><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>FF:FF:FF:FF:FF:FF</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 含义：</p><ul><li>发给<strong>当前网络内所有主机</strong></li></ul><hr><h3 id="工作机制" tabindex="-1">工作机制 <a class="header-anchor" href="#工作机制" aria-label="Permalink to “工作机制”">​</a></h3><h4 id="发送端" tabindex="-1">发送端： <a class="header-anchor" href="#发送端" aria-label="Permalink to “发送端：”">​</a></h4><ul><li>在帧头中加入： <ul><li>源 MAC</li><li>目的 MAC</li></ul></li></ul><hr><h4 id="接收端-网卡处理" tabindex="-1">接收端（网卡处理）： <a class="header-anchor" href="#接收端-网卡处理" aria-label="Permalink to “接收端（网卡处理）：”">​</a></h4><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>目的MAC == 本机MAC → 接收  </span></span>
<span class="line"><span>目的MAC != 本机MAC → 丢弃  </span></span>
<span class="line"><span>目的MAC == 广播地址 → 接收</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><hr><h2 id="三、以太网-ii-帧格式-回顾" tabindex="-1">三、以太网 II 帧格式（回顾） <a class="header-anchor" href="#三、以太网-ii-帧格式-回顾" aria-label="Permalink to “三、以太网 II 帧格式（回顾）”">​</a></h2><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>| 目标MAC(6B) | 源MAC(6B) | 类型(2B) | 数据(46~1500B) | FCS(4B) |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="关键点" tabindex="-1">关键点 <a class="header-anchor" href="#关键点" aria-label="Permalink to “关键点”">​</a></h3><ul><li>帧头：14 字节</li><li>数据范围：46 ~ 1500 字节</li><li>FCS： <ul><li>用于差错检测</li><li>❗抓包中看不到（网卡已处理）</li></ul></li></ul><hr><h3 id="类型字段作用" tabindex="-1">类型字段作用 <a class="header-anchor" href="#类型字段作用" aria-label="Permalink to “类型字段作用”">​</a></h3><p>👉 标识上层协议：</p><ul><li>IPv4（0x0800）</li><li>ARP（0x0806）</li><li>IPv6（0x86DD）</li></ul><hr><h2 id="四、数据过大如何处理" tabindex="-1">四、数据过大如何处理 <a class="header-anchor" href="#四、数据过大如何处理" aria-label="Permalink to “四、数据过大如何处理”">​</a></h2><p>👉 超过 1500 字节：</p><ul><li>上层（网络层）进行： <ul><li><strong>分片（Fragmentation）</strong></li></ul></li></ul><hr><h2 id="五、数据链路层核心协议" tabindex="-1">五、数据链路层核心协议 <a class="header-anchor" href="#五、数据链路层核心协议" aria-label="Permalink to “五、数据链路层核心协议”">​</a></h2><hr><h2 id="_1️⃣-csma-cd-碰撞检测" tabindex="-1">1️⃣ CSMA/CD（碰撞检测） <a class="header-anchor" href="#_1️⃣-csma-cd-碰撞检测" aria-label="Permalink to “1️⃣ CSMA/CD（碰撞检测）”">​</a></h2><h3 id="全称" tabindex="-1">全称 <a class="header-anchor" href="#全称" aria-label="Permalink to “全称”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Carrier Sense Multiple Access with Collision Detection</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to “适用场景”">​</a></h3><p>👉 <strong>有线局域网（共享总线以太网）</strong></p><hr><h3 id="核心问题" tabindex="-1">核心问题 <a class="header-anchor" href="#核心问题" aria-label="Permalink to “核心问题”">​</a></h3><blockquote><p>多台主机共享一条通信介质 → 容易发生碰撞</p></blockquote><hr><h3 id="工作机制-1" tabindex="-1">工作机制 <a class="header-anchor" href="#工作机制-1" aria-label="Permalink to “工作机制”">​</a></h3><ol><li>发送前监听信道（载波监听）</li><li>空闲才发送</li><li>发送过程中检测碰撞</li><li>若发生碰撞： <ul><li>停止发送</li><li>随机等待</li><li>重新发送</li></ul></li></ol><hr><h3 id="本质" tabindex="-1">本质 <a class="header-anchor" href="#本质" aria-label="Permalink to “本质”">​</a></h3><blockquote><p><strong>“先发 + 发现冲突再处理”</strong></p></blockquote><hr><h2 id="_2️⃣-csma-ca-碰撞避免" tabindex="-1">2️⃣ CSMA/CA（碰撞避免） <a class="header-anchor" href="#_2️⃣-csma-ca-碰撞避免" aria-label="Permalink to “2️⃣ CSMA/CA（碰撞避免）”">​</a></h2><h3 id="全称-1" tabindex="-1">全称 <a class="header-anchor" href="#全称-1" aria-label="Permalink to “全称”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Carrier Sense Multiple Access with Collision Avoidance</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="适用场景-1" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景-1" aria-label="Permalink to “适用场景”">​</a></h3><p>👉 <strong>无线局域网（WiFi）</strong></p><hr><h3 id="为什么不用-cd" tabindex="-1">为什么不用 CD？ <a class="header-anchor" href="#为什么不用-cd" aria-label="Permalink to “为什么不用 CD？”">​</a></h3><ul><li>无线环境： <ul><li>难以检测碰撞</li><li>硬件成本高</li><li>检测不准确</li></ul></li></ul><hr><h3 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to “核心思想”">​</a></h3><blockquote><p><strong>尽量避免碰撞，而不是检测碰撞</strong></p></blockquote><hr><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to “特点”">​</a></h3><ul><li>通过等待、控制发送时机降低冲突概率</li><li>❗不能完全避免碰撞</li></ul><hr><h3 id="对比总结" tabindex="-1">对比总结 <a class="header-anchor" href="#对比总结" aria-label="Permalink to “对比总结”">​</a></h3><table tabindex="0"><thead><tr><th>协议</th><th>场景</th><th>思想</th></tr></thead><tbody><tr><td>CSMA/CD</td><td>有线</td><td>先发 → 检测冲突</td></tr><tr><td>CSMA/CA</td><td>无线</td><td>先避免 → 再发</td></tr></tbody></table><hr><h2 id="_3️⃣-ppp-点对点协议" tabindex="-1">3️⃣ PPP（点对点协议） <a class="header-anchor" href="#_3️⃣-ppp-点对点协议" aria-label="Permalink to “3️⃣ PPP（点对点协议）”">​</a></h2><h3 id="全称-2" tabindex="-1">全称 <a class="header-anchor" href="#全称-2" aria-label="Permalink to “全称”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Point-to-Point Protocol</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h3 id="核心特点" tabindex="-1">核心特点 <a class="header-anchor" href="#核心特点" aria-label="Permalink to “核心特点”">​</a></h3><blockquote><p><strong>用于两点之间直接通信</strong></p></blockquote><hr><h3 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to “应用场景”">​</a></h3><h4 id="_1️⃣-主机-↔-isp-运营商" tabindex="-1">1️⃣ 主机 ↔ ISP（运营商） <a class="header-anchor" href="#_1️⃣-主机-↔-isp-运营商" aria-label="Permalink to “1️⃣ 主机 ↔ ISP（运营商）”">​</a></h4><ul><li>常见形式：</li></ul><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>PPPoE（PPP over Ethernet）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 示例：</p><ul><li>家庭宽带拨号</li><li>路由器上网方式</li></ul><hr><h4 id="_2️⃣-路由器-↔-路由器" tabindex="-1">2️⃣ 路由器 ↔ 路由器 <a class="header-anchor" href="#_2️⃣-路由器-↔-路由器" aria-label="Permalink to “2️⃣ 路由器 ↔ 路由器”">​</a></h4><ul><li>点对点链路通信</li></ul><hr><h2 id="六、实践补充-路由器访问" tabindex="-1">六、实践补充（路由器访问） <a class="header-anchor" href="#六、实践补充-路由器访问" aria-label="Permalink to “六、实践补充（路由器访问）”">​</a></h2><h3 id="查找路由器-ip" tabindex="-1">查找路由器 IP <a class="header-anchor" href="#查找路由器-ip" aria-label="Permalink to “查找路由器 IP”">​</a></h3><p>Windows：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ipconfig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /all</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 关键字段：</p><ul><li>默认网关 = 路由器 IP</li></ul><hr><h3 id="访问方式" tabindex="-1">访问方式 <a class="header-anchor" href="#访问方式" aria-label="Permalink to “访问方式”">​</a></h3><p>浏览器输入：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>http://默认网关地址</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="七、整体流程总结" tabindex="-1">七、整体流程总结 <a class="header-anchor" href="#七、整体流程总结" aria-label="Permalink to “七、整体流程总结”">​</a></h2><h3 id="数据链路层工作流程" tabindex="-1">数据链路层工作流程 <a class="header-anchor" href="#数据链路层工作流程" aria-label="Permalink to “数据链路层工作流程”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>封装帧 → 添加MAC地址 → 发送 → 接收 → 校验 → 解封装</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="八、本节核心总结" tabindex="-1">八、本节核心总结 <a class="header-anchor" href="#八、本节核心总结" aria-label="Permalink to “八、本节核心总结”">​</a></h2><h3 id="_1️⃣-数据链路层解决的问题" tabindex="-1">1️⃣ 数据链路层解决的问题 <a class="header-anchor" href="#_1️⃣-数据链路层解决的问题" aria-label="Permalink to “1️⃣ 数据链路层解决的问题”">​</a></h3><blockquote><p><strong>同一链路（局域网）内如何可靠传输数据</strong></p></blockquote><hr><h3 id="_2️⃣-三大核心机制" tabindex="-1">2️⃣ 三大核心机制 <a class="header-anchor" href="#_2️⃣-三大核心机制" aria-label="Permalink to “2️⃣ 三大核心机制”">​</a></h3><ul><li>MAC 地址 → 标识设备</li><li>帧结构 → 组织数据</li><li>协议（CSMA/CD、CA、PPP） → 控制通信</li></ul><hr><h3 id="_3️⃣-最关键理解" tabindex="-1">3️⃣ 最关键理解 <a class="header-anchor" href="#_3️⃣-最关键理解" aria-label="Permalink to “3️⃣ 最关键理解”">​</a></h3><blockquote><p><strong>数据链路层 = 局域网通信规则制定者</strong></p></blockquote><hr><h3 id="_4️⃣-一句话总结" tabindex="-1">4️⃣ 一句话总结 <a class="header-anchor" href="#_4️⃣-一句话总结" aria-label="Permalink to “4️⃣ 一句话总结”">​</a></h3><blockquote><p><strong>链路层通过 MAC 地址 + 帧格式 + 协议，实现局域网内高效可靠通信</strong></p></blockquote><hr><p>如果你下一步继续学，建议重点跟进：</p><p>👉 <strong>ARP 协议（IP → MAC 映射）</strong></p><p>这是连接“网络层”和“数据链路层”的关键桥梁。</p>`,127)])])}const u=i(r,[["render",n]]);export{p as __pageData,u as default};
